import { Component, OnInit, OnDestroy, HostListener } from '@angular/core';
import { Subject } from 'rxjs';
import { takeUntil } from 'rxjs/operators';
import { JobService } from '../services/job.service';
import { DiceApiService } from '../services/dice-api.service';
import { CoverLetterService } from '../services/cover-letter.service';
import { Job, JobDecision } from '../models/job.model';

@Component({
  selector: 'app-easy-apply-workflow',
  templateUrl: './easy-apply-workflow.component.html',
  styleUrls: ['./easy-apply-workflow.component.css']
})
export class EasyApplyWorkflowComponent implements OnInit, OnDestroy {
  currentJob: Job | null = null;
  jobs: Job[] = [];
  jobStats = { total: 0, pending: 0, applied: 0, skipped: 0 };
  isLoading = false;
  coverLetterMode: 'AI' | 'Template' | null = null;
  generatedCoverLetter = '';
  savedCoverLetterPath = '';
  jobDescription = '';
  showReview = false;
  currentStep: 'cover-letter' | 'review' | 'decision' = 'cover-letter';
  decisionNotes = '';
  skipReason = '';
  showSettings = false;
  showDescriptionModal = false;
  geminiApiKey = '';
  isSavingDecision = false;
  toastMessage = '';
  toastType: 'success' | 'error' = 'success';
  showToast = false;
  private toastTimer: ReturnType<typeof setTimeout> | null = null;

  private destroy$ = new Subject<void>();

  constructor(
    private jobService: JobService,
    private diceApi: DiceApiService,
    private coverLetterService: CoverLetterService
  ) { }

  ngOnInit(): void {
    this.subscribeToJobUpdates();
    this.loadGeminiApiKey();

    // If a job was pre-selected (e.g. from grid row click), use it directly
    const preSelected = this.jobService.getCurrentJob();
    if (preSelected) {
      this.resetWorkflow();
      this.currentJob = preSelected;
      this.fetchJobDescription(preSelected);
      this.updateStats();
    } else {
      this.loadJobs();
    }
  }

  ngOnDestroy(): void {
    if (this.toastTimer) {
      clearTimeout(this.toastTimer);
      this.toastTimer = null;
    }
    this.destroy$.next();
    this.destroy$.complete();
  }

  @HostListener('document:keydown.escape')
  onEscapeKey(): void {
    if (this.showDescriptionModal) {
      this.closeDescriptionModal();
    }
  }

  loadJobs(): void {
    this.isLoading = true;
    this.diceApi.searchEasyApplyJobs()
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (jobs) => {
          this.jobService.setJobs(jobs);
          this.nextJob();
          this.isLoading = false;
        },
        error: (err) => {
          console.error('Error loading jobs:', err);
          this.nextJob();
          this.isLoading = false;
        }
      });
  }

  private subscribeToJobUpdates(): void {
    this.jobService.jobs$
      .pipe(takeUntil(this.destroy$))
      .subscribe(jobs => {
        this.jobs = jobs;
        this.updateStats();
      });
  }

  private updateStats(): void {
    this.jobStats = this.jobService.getJobStats();
  }

  private loadGeminiApiKey(): void {
    this.geminiApiKey = localStorage.getItem('gemini_api_key') || '';
  }

  nextJob(): void {
    this.resetWorkflow();
    this.currentJob = null;
    const job = this.jobService.nextPendingJob();
    if (job) {
      this.currentJob = job;
      this.fetchJobDescription(job);
    }
  }

  private resetWorkflow(): void {
    this.coverLetterMode = null;
    this.generatedCoverLetter = '';
    this.savedCoverLetterPath = '';
    this.jobDescription = '';
    this.showReview = false;
    this.currentStep = 'cover-letter';
    this.decisionNotes = '';
    this.skipReason = '';
    this.isSavingDecision = false;
    this.showDescriptionModal = false;
  }

  openDescriptionModal(): void {
    this.showDescriptionModal = true;
  }

  closeDescriptionModal(): void {
    this.showDescriptionModal = false;
  }

  private fetchJobDescription(job: Job): void {
    this.isLoading = true;
    this.diceApi.getJobDescription(job)
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (desc) => {
          this.jobDescription = desc || 'Job description not available';
          this.isLoading = false;
        },
        error: () => {
          this.jobDescription = 'Could not fetch job description';
          this.isLoading = false;
        }
      });
  }

  selectCoverLetterMode(mode: 'AI' | 'Template' | null): void {
    this.coverLetterMode = mode;
    if (mode === null) {
      this.currentStep = 'review';
      this.generatedCoverLetter = '';
    } else {
      this.generateCoverLetter(mode);
    }
  }

  private generateCoverLetter(mode: 'AI' | 'Template'): void {
    if (!this.currentJob) return;

    this.isLoading = true;
    this.savedCoverLetterPath = '';

    const saveAfterGenerate = (letter: string) => {
      this.generatedCoverLetter = letter;
      this.coverLetterService
        .saveCoverLetterAsTxt(this.currentJob!, letter, mode)
        .pipe(takeUntil(this.destroy$))
        .subscribe({
          next: (savedPath) => {
            this.savedCoverLetterPath = savedPath || '';
            this.isLoading = false;
          },
          error: () => { this.isLoading = false; }
        });
    };

    if (mode === 'AI') {
      this.coverLetterService.generateAICoverLetter(this.currentJob, this.jobDescription)
        .pipe(takeUntil(this.destroy$))
        .subscribe({
          next: (letter) => saveAfterGenerate(letter || this.getDefaultCoverLetter()),
          error: () => saveAfterGenerate(this.getDefaultCoverLetter())
        });
    } else {
      this.coverLetterService.generateTemplateCoverLetter(this.currentJob)
        .pipe(takeUntil(this.destroy$))
        .subscribe({
          next: (letter) => saveAfterGenerate(letter)
        });
    }
  }

  private getDefaultCoverLetter(): string {
    if (!this.currentJob) return '';
    const template = `Professional cover letter for ${this.currentJob.role} at ${this.currentJob.company}`;
    return template;
  }

  proceedToDecision(): void {
    this.currentStep = 'decision';
  }

  recordDecision(decision: 'Applied' | 'Skipped' | 'Pending'): void {
    if (!this.currentJob || this.isSavingDecision) return;
    this.finalizeDecision(decision, this.savedCoverLetterPath || undefined);
  }

  private showDecisionToast(message: string, type: 'success' | 'error'): void {
    this.toastMessage = message;
    this.toastType = type;
    this.showToast = true;

    if (this.toastTimer) {
      clearTimeout(this.toastTimer);
    }

    this.toastTimer = setTimeout(() => {
      this.showToast = false;
      this.toastTimer = null;
    }, 3000);
  }

  private finalizeDecision(decision: 'Applied' | 'Skipped' | 'Pending', coverLetterPath?: string): void {
    if (!this.currentJob) return;

    const selectedJob = this.currentJob;
    this.isSavingDecision = true;

    const jobDecision: JobDecision = {
      link: selectedJob.link,
      decision,
      company: selectedJob.company,
      role: selectedJob.role,
      location: selectedJob.location,
      notes: this.decisionNotes,
      skipReason: decision === 'Skipped' ? this.skipReason : undefined,
      coverLetterPath: coverLetterPath || undefined,
      timestamp: new Date().toISOString()
    };

    // Persist status change back to tracker CSV first.
    this.diceApi.updateJobStatus(selectedJob.link, decision)
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: () => {
          this.jobService.recordDecision(jobDecision);
          this.updateStats();
          this.showDecisionToast(`${decision} saved. Moving to next job...`, 'success');
          this.isSavingDecision = false;
          this.nextJob();
        },
        error: () => {
          this.isSavingDecision = false;
          this.showDecisionToast(`Failed to save ${decision}. Please try again.`, 'error');
        }
      });
  }

  saveGeminiApiKey(): void {
    this.coverLetterService.setGeminiApiKey(this.geminiApiKey);
    this.showSettings = false;
    alert('API key saved successfully!');
  }

  toggleSettings(): void {
    this.showSettings = !this.showSettings;
  }

  clearAllData(): void {
    if (confirm('Are you sure you want to clear all data? This cannot be undone.')) {
      this.jobService.clearAllData();
      this.resetWorkflow();
      this.updateStats();
      this.nextJob();
    }
  }
}
<div class="workflow-container">
  <!-- Header -->
  <div class="header">
    <div class="header-content">
      <div class="title-group">
        <h1>Dice Easy Apply Workflow</h1>
        <p class="subtitle">Tracker-driven queue for To Apply jobs</p>
      </div>
      <div class="stats">
        <div class="stat-item">
          <span class="stat-label">Total:</span>
          <span class="stat-value">{{ jobStats.total }}</span>
        </div>
        <div class="stat-item">
          <span class="stat-label">Pending:</span>
          <span class="stat-value pending">{{ jobStats.pending }}</span>
        </div>
        <div class="stat-item">
          <span class="stat-label">Applied:</span>
          <span class="stat-value applied">{{ jobStats.applied }}</span>
        </div>
        <div class="stat-item">
          <span class="stat-label">Skipped:</span>
          <span class="stat-value skipped">{{ jobStats.skipped }}</span>
        </div>
      </div>
      <div class="header-actions">
        <button class="refresh-btn" (click)="loadJobs()" [disabled]="isLoading">Refresh Tracker</button>
        <button class="settings-btn" (click)="toggleSettings()">Settings</button>
      </div>
    </div>
  </div>

  <!-- Settings Panel -->
  <div *ngIf="showSettings" class="settings-panel">
    <h3>Settings</h3>
    <div class="settings-form">
      <label for="gemini-key">Google Gemini API Key:</label>
      <input
        id="gemini-key"
        type="password"
        [(ngModel)]="geminiApiKey"
        placeholder="Enter your Gemini API key"
        class="input-field"
      />
      <div class="button-group">
        <button (click)="saveGeminiApiKey()" class="btn-primary">Save Key</button>
        <button (click)="toggleSettings()" class="btn-secondary">Cancel</button>
        <button (click)="clearAllData()" class="btn-danger">Clear All Data</button>
      </div>
    </div>
  </div>

  <!-- Main Content -->
  <div class="main-content" *ngIf="!showSettings">
    <div *ngIf="showToast" class="decision-toast" [class.error]="toastType === 'error'" [class.success]="toastType === 'success'">
      {{ toastMessage }}
    </div>

    <div *ngIf="!currentJob" class="no-jobs">
      <p>✅ No pending jobs to process. Great work!</p>
      <button (click)="loadJobs()" class="btn-primary">Load New Jobs</button>
    </div>

    <div *ngIf="currentJob" class="job-workflow">
      <!-- Job Details -->
      <div class="job-card">
        <div class="job-header">
          <h2 [class.fallback-title]="!currentJob.role">{{ currentJob.role || 'Role Not Available' }}</h2>
          <div class="job-meta">
            <span class="company">{{ currentJob.company || 'Company Not Available' }}</span>
            <span class="location">{{ currentJob.location || 'Location Not Available' }}</span>
          </div>
        </div>

        <div class="quick-facts">
          <div class="fact-chip"><span class="chip-label">Score</span><span class="chip-value">{{ currentJob.score || 0 }}</span></div>
          <div class="fact-chip"><span class="chip-label">Work</span><span class="chip-value">{{ currentJob.workType || 'Unknown' }}</span></div>
          <div class="fact-chip"><span class="chip-label">Salary</span><span class="chip-value">{{ currentJob.salary || 'Not specified' }}</span></div>
        </div>

        <details class="compact-extra">
          <summary>More job details</summary>
          <div class="job-info">
            <div class="info-row">
              <span class="label">Summary:</span>
              <span class="value">{{ currentJob.summary || 'No summary' }}</span>
            </div>
          </div>
        </details>

        <div class="job-link">
          <a [href]="currentJob.link" target="_blank" class="link">View on Dice →</a>
        </div>
      </div>

      <!-- Job Description -->
      <div class="job-description-card compact-description-card">
        <div class="description-row">
          <span class="description-title">Job Description</span>
          <button class="btn-secondary" (click)="openDescriptionModal()">Open Modal</button>
        </div>
      </div>

      <!-- Workflow Steps -->
      <div class="workflow-steps">
        <div class="workflow-title-row">
          <h3>Quick Apply Flow</h3>
          <span class="workflow-hint">Generate cover letter then decide</span>
        </div>

        <!-- Step 1: Cover Letter -->
        <div class="step cover-letter-step">
          <h4>Step 1: Cover Letter</h4>
          <div class="step1-layout">
            <div class="cover-letter-actions">
              <div class="button-group">
                <button
                  (click)="selectCoverLetterMode('AI')"
                  class="btn-primary"
                  [disabled]="isLoading"
                >
                  🤖 AI Generated
                </button>
                <button
                  (click)="selectCoverLetterMode('Template')"
                  class="btn-primary"
                  [disabled]="isLoading"
                >
                  📄 Template
                </button>
              </div>
              <div *ngIf="isLoading" class="loading">⏳ Generating cover letter...</div>
            </div>
            <div class="cover-letter-preview-box">
              <h5>Preview</h5>
              <div
                class="cover-letter-preview"
                [textContent]="generatedCoverLetter || 'No cover letter generated yet.'"
              ></div>
            </div>
          </div>
        </div>

        <!-- Step 2: Decision -->
        <div class="step decision-step">
          <h4>Step 2: Make Decision</h4>

          <div class="decision-meta">
            <div class="meta-item">
              <span class="meta-label">Job:</span>
              <span class="job-link-actions">
                <a *ngIf="currentJob?.link" [href]="currentJob.link" target="_blank" rel="noopener" class="meta-link open-link">Open on Dice ↗</a>
              </span>
              <span *ngIf="!currentJob?.link" class="meta-none">N/A</span>
            </div>
            <div class="meta-item" *ngIf="savedCoverLetterPath">
              <span class="meta-label">Letter:</span>
              <span class="meta-file">{{ savedCoverLetterPath }}</span>
            </div>
            <div class="meta-item" *ngIf="generatedCoverLetter && !savedCoverLetterPath">
              <span class="meta-label">Letter:</span>
              <span class="meta-file meta-unsaved">Saving...</span>
            </div>
            <div class="meta-item" *ngIf="!generatedCoverLetter">
              <span class="meta-label">Letter:</span>
              <span class="meta-none">Not generated</span>
            </div>
          </div>

          <details class="optional-fields">
            <summary>Optional notes and skip reason</summary>
            <div class="form-group">
              <label for="notes">Note:</label>
              <textarea
                id="notes"
                [(ngModel)]="decisionNotes"
                placeholder="Add any notes about this job"
                rows="2"
                class="input-field"
              ></textarea>
            </div>

            <div class="form-group">
              <label for="skip-reason">Skip reason:</label>
              <select id="skip-reason" [(ngModel)]="skipReason" class="input-field">
                <option value="">Select a reason...</option>
                <option value="clearance">Security clearance required</option>
                <option value="low-salary">Low salary</option>
                <option value="onsite">Onsite only</option>
                <option value="bad-fit">Bad fit</option>
                <option value="other">Other</option>
              </select>
            </div>
          </details>

          <div class="decision-buttons decision-bar">
            <button (click)="recordDecision('Applied')" class="btn-applied" [disabled]="isSavingDecision || isLoading">
              {{ isSavingDecision ? 'Saving...' : '✅ Apply' }}
            </button>
            <button (click)="recordDecision('Skipped')" class="btn-skipped" [disabled]="isSavingDecision || isLoading">
              {{ isSavingDecision ? 'Saving...' : '❌ Skip' }}
            </button>
            <button (click)="recordDecision('Pending')" class="btn-secondary" [disabled]="isSavingDecision || isLoading">
              {{ isSavingDecision ? 'Saving...' : '⏸️ Pending' }}
            </button>
          </div>
        </div>
      </div>
    </div>

    <div *ngIf="showDescriptionModal" class="description-modal-overlay" (click)="closeDescriptionModal()">
      <div class="description-modal" role="dialog" aria-modal="true" aria-label="Job Description" (click)="$event.stopPropagation()">
        <div class="description-modal-header">
          <h3>Job Description</h3>
          <button class="modal-close-btn" (click)="closeDescriptionModal()">✕</button>
        </div>
        <div class="description-modal-content" [textContent]="jobDescription || 'Job description not available'" ></div>
      </div>
    </div>
  </div>
</div>
